/* Custom HTML5 Canvas BillingChart Library - Mimics Chart.js */
class BillingChart {
    constructor(canvasId, config) {
        this.canvas = typeof canvasId === 'string' ? document.getElementById(canvasId) : canvasId;
        if (!this.canvas) return;
        this.config = config;
        this.render();
        
        // Handle resizing
        window.addEventListener('resize', () => {
            this.render();
        });
    }
    
    render() {
        const ctx = this.canvas.getContext('2d');
        const parent = this.canvas.parentElement;
        const width = this.canvas.width = parent.clientWidth || 400;
        const height = this.canvas.height = 250;
        
        ctx.clearRect(0, 0, width, height);
        
        const type = this.config.type || 'line';
        const labels = this.config.data.labels || [];
        const datasets = this.config.data.datasets || [];
        if (datasets.length === 0) return;
        
        const data = datasets[0].data || [];
        if (data.length === 0) return;
        
        const maxVal = Math.max(...data, 100) * 1.15; // Padding for height
        const padding = { top: 25, right: 20, bottom: 40, left: 55 };
        const chartWidth = width - padding.left - padding.right;
        const chartHeight = height - padding.top - padding.bottom;
        
        // Draw grid lines
        ctx.strokeStyle = '#334155'; // border-color
        ctx.lineWidth = 1;
        ctx.fillStyle = '#94a3b8'; // text-secondary
        ctx.font = '10px sans-serif';
        ctx.textAlign = 'right';
        
        // Y Axis Grid & Labels (5 grids)
        for (let i = 0; i <= 4; i++) {
            const val = (maxVal * i / 4).toFixed(0);
            const y = padding.top + chartHeight - (chartHeight * i / 4);
            ctx.fillText(val, padding.left - 10, y + 4);
            ctx.beginPath();
            ctx.moveTo(padding.left, y);
            ctx.lineTo(padding.left + chartWidth, y);
            ctx.stroke();
        }
        
        // X Axis labels
        ctx.textAlign = 'center';
        const stepX = labels.length > 1 ? chartWidth / (labels.length - 1) : chartWidth;
        labels.forEach((lbl, idx) => {
            const x = padding.left + (idx * stepX);
            // Draw every alternate/spaced label if there are too many labels
            if (labels.length < 15 || idx % Math.ceil(labels.length / 8) === 0) {
                ctx.fillText(lbl, x, padding.top + chartHeight + 18);
            }
        });
        
        // Draw Data
        if (type === 'line') {
            // Area and Line Chart
            ctx.strokeStyle = '#3b82f6'; // blue-500
            ctx.lineWidth = 3;
            ctx.beginPath();
            
            data.forEach((val, idx) => {
                const x = padding.left + (idx * stepX);
                const y = padding.top + chartHeight - (chartHeight * val / maxVal);
                if (idx === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }
            });
            ctx.stroke();
            
            // Draw gradient below line
            const gradient = ctx.createLinearGradient(0, padding.top, 0, padding.top + chartHeight);
            gradient.addColorStop(0, 'rgba(59, 130, 246, 0.35)');
            gradient.addColorStop(1, 'rgba(59, 130, 246, 0.00)');
            ctx.fillStyle = gradient;
            
            // Close the path along base line
            if (data.length > 0) {
                ctx.lineTo(padding.left + ((data.length - 1) * stepX), padding.top + chartHeight);
                ctx.lineTo(padding.left, padding.top + chartHeight);
            }
            ctx.closePath();
            ctx.fill();
            
            // Draw circles on points
            ctx.fillStyle = '#60a5fa'; // blue-400
            data.forEach((val, idx) => {
                const x = padding.left + (idx * stepX);
                const y = padding.top + chartHeight - (chartHeight * val / maxVal);
                ctx.beginPath();
                ctx.arc(x, y, 4, 0, Math.PI * 2);
                ctx.fill();
            });
            
        } else if (type === 'bar') {
            // Bar Chart
            const count = data.length;
            const colWidth = chartWidth / count;
            const barWidth = colWidth * 0.65;
            const gap = colWidth * 0.35;
            
            const barGradient = ctx.createLinearGradient(0, padding.top, 0, padding.top + chartHeight);
            barGradient.addColorStop(0, '#3b82f6');
            barGradient.addColorStop(1, '#1d4ed8');
            ctx.fillStyle = barGradient;
            
            data.forEach((val, idx) => {
                const x = padding.left + (idx * colWidth) + gap / 2;
                const y = padding.top + chartHeight - (chartHeight * val / maxVal);
                const barHeight = chartHeight * val / maxVal;
                
                ctx.beginPath();
                if (ctx.roundRect) {
                    ctx.roundRect(x, y, barWidth, barHeight, [4, 4, 0, 0]);
                } else {
                    ctx.rect(x, y, barWidth, barHeight);
                }
                ctx.fill();
            });
        }
    }
}

// Export globally so it acts as standard Chart.js
window.Chart = BillingChart;
